import React, { useEffect, useState, useContext } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { AuthContext } from '../../context/AuthContext';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

const AddProduct = () => {
  const navigate = useNavigate();
  const { user, logout } = useContext(AuthContext || {});
  const [categories, setCategories] = useState([]);
  const [loadingCategories, setLoadingCategories] = useState(true);

  const [name, setName] = useState('');
  const [flowerType, setFlowerType] = useState('');
  const [season, setSeason] = useState('Quanh năm');
  const [categoryId, setCategoryId] = useState('');
  const [price, setPrice] = useState('');
  const [discountPrice, setDiscountPrice] = useState('');
  const [stock, setStock] = useState(0);
  const [isFeatured, setIsFeatured] = useState(false);
  const [tagsInput, setTagsInput] = useState('');
  const [tags, setTags] = useState([]);
  const [description, setDescription] = useState('');

  const [files, setFiles] = useState([]);
  const [previews, setPreviews] = useState([]);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    const fetchCats = async () => {
      try {
        const res = await axios.get(`${API_URL}/api/categories`);
        const cats = Array.isArray(res.data) ? res.data : res.data.categories || [];
        setCategories(cats);
        if (cats.length) setCategoryId(cats[0]._id || cats[0].id || '');
      } catch (err) {
        console.error('Load categories error', err);
      } finally {
        setLoadingCategories(false);
      }
    };
    fetchCats();
  }, []);

  useEffect(() => {
    if (!files || files.length === 0) {
      setPreviews([]);
      return;
    }
    setPreviews([]);
    files.forEach(file => {
      const reader = new FileReader();
      reader.onload = (e) => setPreviews(prev => [...prev, e.target.result]);
      reader.readAsDataURL(file);
    });
  }, [files]);

  useEffect(() => {
    const arr = tagsInput.split(',').map(t => t.trim()).filter(t => t);
    setTags(arr);
  }, [tagsInput]);

  const handleFilesChange = (e) => setFiles(Array.from(e.target.files || []));
  const removePreviewAt = (i) => {
    setFiles(prev => prev.filter((_, idx) => idx !== i));
    setPreviews(prev => prev.filter((_, idx) => idx !== i));
  };

  const getToken = () => {
    try {
      return user?.token || JSON.parse(localStorage.getItem('userInfo'))?.token;
    } catch {
      return null;
    }
  };

  const handleSubmit = async (e) => {
  e.preventDefault();
  if (!name || !categoryId || !price || !description) {
    setError('Vui lòng điền đầy đủ các trường có dấu *');
    return;
  }

  const token = getToken();
  if (!token) {
    alert('Bạn chưa đăng nhập hoặc phiên hết hạn. Vui lòng đăng nhập lại.');
    if (logout) logout();
    return;
  }

  try {
    setSubmitting(true);
    let imageUrls = [];

    // 🖼️ 1️⃣ Upload ảnh trước nếu có file
    if (files.length > 0) {
      const imgForm = new FormData();
      files.forEach(f => imgForm.append('images', f));

      const uploadRes = await axios.post(`${API_URL}/api/upload`, imgForm, {
        headers: {
          'Content-Type': 'multipart/form-data',
          Authorization: `Bearer ${token}`,
        },
      });

      imageUrls = uploadRes.data.urls || []; // nhận mảng URL ảnh từ backend
    }

    // 🌷 2️⃣ Gửi dữ liệu sản phẩm
    const productData = {
      name,
      description,
      price: Number(price),
      discountPrice: discountPrice ? Number(discountPrice) : undefined,
      categoryId,
      flowerType,
      season,
      stock: Number(stock),
      isFeatured,
      tags,
      images: imageUrls, // thêm danh sách ảnh từ upload
    };

    const res = await axios.post(`${API_URL}/api/products`, productData, {
      headers: {
        Authorization: `Bearer ${token}`,
      },
    });

    alert('🌸 Thêm sản phẩm thành công!');
    navigate('/admin/products');
  } catch (err) {
    console.error('Upload hoặc thêm sản phẩm lỗi:', err);
    setError(err?.response?.data?.message || 'Lỗi khi thêm sản phẩm');
  } finally {
    setSubmitting(false);
  }
};


  return (
    <div className="min-h-screen bg-gradient-to-br from-pink-50 to-blue-50 py-10 px-4">
      <div className="max-w-4xl mx-auto bg-white/80 backdrop-blur-md shadow-lg rounded-2xl p-8 border border-gray-100">
        <h2 className="text-3xl font-semibold text-gray-800 mb-6 text-center">🌸 Thêm Sản Phẩm Mới</h2>

        {error && (
          <div className="mb-4 text-red-600 bg-red-100 border border-red-300 p-3 rounded-lg">
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="grid grid-cols-2 gap-6">
            {/* Tên sản phẩm */}
            <div>
              <label className="block font-medium text-gray-700 mb-1">Tên sản phẩm *</label>
              <input value={name} onChange={e => setName(e.target.value)} className="w-full border border-gray-300 focus:border-pink-400 focus:ring focus:ring-pink-100 rounded-lg px-3 py-2 outline-none transition" />
            </div>

            {/* Danh mục */}
            <div>
              <label className="block font-medium text-gray-700 mb-1">Danh mục *</label>
              <select value={categoryId} onChange={e => setCategoryId(e.target.value)} className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:border-blue-400 focus:ring focus:ring-blue-100 outline-none transition">
                {loadingCategories ? (
                  <option>Đang tải...</option>
                ) : (
                  categories.map(c => <option key={c._id || c.id} value={c._id || c.id}>{c.name}</option>)
                )}
              </select>
            </div>

            {/* Giá */}
            <div>
              <label className="block font-medium text-gray-700 mb-1">Giá gốc *</label>
              <input type="number" min="0" value={price} onChange={e => setPrice(e.target.value)} className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:border-green-400 focus:ring focus:ring-green-100 outline-none transition" />
            </div>

            {/* Giá KM */}
            <div>
              <label className="block font-medium text-gray-700 mb-1">Giá khuyến mãi</label>
              <input type="number" min="0" value={discountPrice} onChange={e => setDiscountPrice(e.target.value)} className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:border-green-400 focus:ring focus:ring-green-100 outline-none transition" />
            </div>

            {/* Tồn kho */}
            <div>
              <label className="block font-medium text-gray-700 mb-1">Tồn kho</label>
              <input type="number" min="0" value={stock} onChange={e => setStock(e.target.value)} className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:border-purple-400 focus:ring focus:ring-purple-100 outline-none transition" />
            </div>

            {/* Loại hoa */}
            <div>
              <label className="block font-medium text-gray-700 mb-1">Loại hoa</label>
              <input value={flowerType} onChange={e => setFlowerType(e.target.value)} className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:border-purple-400 focus:ring focus:ring-purple-100 outline-none transition" />
            </div>

            {/* Mùa */}
            <div>
              <label className="block font-medium text-gray-700 mb-1">Mùa</label>
              <select value={season} onChange={e => setSeason(e.target.value)} className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:border-pink-400 focus:ring focus:ring-pink-100 outline-none transition">
                <option>Quanh năm</option>
                <option>Xuân</option>
                <option>Hạ</option>
                <option>Thu</option>
                <option>Đông</option>
              </select>
            </div>

            {/* Tags */}
            <div className="col-span-2">
              <label className="block font-medium text-gray-700 mb-1">Tags (ngăn cách bằng dấu phẩy)</label>
              <input value={tagsInput} onChange={e => setTagsInput(e.target.value)} placeholder="Ví dụ: quà tặng, sinh nhật, tình yêu" className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:border-blue-400 focus:ring focus:ring-blue-100 outline-none transition" />
              {tags.length > 0 && (
                <div className="mt-2 flex flex-wrap gap-2">
                  {tags.map((t, i) => (
                    <span key={i} className="text-sm bg-pink-100 text-pink-700 px-2 py-1 rounded-lg">{t}</span>
                  ))}
                </div>
              )}
            </div>
          </div>

          {/* Mô tả */}
          <div>
            <label className="block font-medium text-gray-700 mb-1">Mô tả *</label>
            <textarea value={description} onChange={e => setDescription(e.target.value)} rows="6" className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:border-pink-400 focus:ring focus:ring-pink-100 outline-none transition" />
          </div>

          {/* Ảnh */}
          <div>
            <label className="block font-medium text-gray-700 mb-1">Hình ảnh (tối đa 5 ảnh)</label>
            <input type="file" accept="image/*" multiple onChange={handleFilesChange} className="block w-full border border-gray-200 rounded-lg p-2 bg-gray-50 hover:bg-gray-100 cursor-pointer transition" />
            {previews.length > 0 && (
              <div className="mt-3 grid grid-cols-5 gap-3">
                {previews.map((p, i) => (
                  <div key={i} className="relative group">
                    <img src={p} alt="" className="w-28 h-28 object-cover rounded-lg border border-gray-200 shadow-sm" />
                    <button type="button" onClick={() => removePreviewAt(i)} className="absolute top-1 right-1 bg-white/80 hover:bg-red-500 hover:text-white text-red-500 rounded-full p-1 shadow transition">✕</button>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Nổi bật */}
          <div className="flex items-center gap-3">
            <input id="featured" type="checkbox" checked={isFeatured} onChange={e => setIsFeatured(e.target.checked)} className="w-4 h-4 accent-pink-500" />
            <label htmlFor="featured" className="text-gray-700">Sản phẩm nổi bật</label>
          </div>

          {/* Buttons */}
          <div className="flex justify-end gap-3">
            <button type="button" onClick={() => navigate('/admin/products')} className="px-5 py-2 rounded-lg bg-gray-200 text-gray-700 hover:bg-gray-300 transition">Hủy</button>
            <button type="submit" disabled={submitting} className="px-6 py-2 rounded-lg bg-pink-500 text-white font-medium hover:bg-pink-600 shadow transition">
              {submitting ? 'Đang lưu...' : 'Thêm sản phẩm'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default AddProduct;
